import{_ as e,o as d,c as a,ak as o}from"./chunks/framework.DiS-pR0X.js";const u=JSON.parse('{"title":"Manual de Administración de Node.js","description":"","frontmatter":{},"headers":[],"relativePath":"programacion/node/administracion.md","filePath":"programacion/node/administracion.md","lastUpdated":1775585594000}'),r={name:"programacion/node/administracion.md"};function i(n,t,c,s,l,p){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="manual-de-administracion-de-node-js" tabindex="-1">Manual de Administración de Node.js <a class="header-anchor" href="#manual-de-administracion-de-node-js" aria-label="Permalink to “Manual de Administración de Node.js”">​</a></h1><div class="info custom-block"><p class="custom-block-title">ℹ️</p><p>Comandos básicos para el administrador</p></div><hr><h2 id="_1-instalacion-y-gestion-de-versiones" tabindex="-1">1. Instalación y Gestión de Versiones <a class="header-anchor" href="#_1-instalacion-y-gestion-de-versiones" aria-label="Permalink to “1. Instalación y Gestión de Versiones”">​</a></h2><h3 id="_1-1-verificar-instalacion" tabindex="-1">1.1 Verificar instalación <a class="header-anchor" href="#_1-1-verificar-instalacion" aria-label="Permalink to “1.1 Verificar instalación”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>node -v</code></td><td>Muestra la versión instalada de Node.js</td></tr><tr><td><code>npm -v</code></td><td>Muestra la versión del gestor de paquetes npm</td></tr><tr><td><code>npx -v</code></td><td>Muestra la versión de npx (ejecutor de paquetes)</td></tr><tr><td><code>node --version</code></td><td>Versión completa de Node.js</td></tr><tr><td><code>which node</code></td><td>Ruta del binario de Node (Linux/macOS)</td></tr><tr><td><code>where node</code></td><td>Ruta del binario de Node (Windows)</td></tr></tbody></table><h3 id="_1-2-nvm-—-node-version-manager" tabindex="-1">1.2 NVM — Node Version Manager <a class="header-anchor" href="#_1-2-nvm-—-node-version-manager" aria-label="Permalink to “1.2 NVM — Node Version Manager”">​</a></h3><p>NVM permite instalar y cambiar entre múltiples versiones de Node.js:</p><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>nvm install 20</code></td><td>Instala Node.js versión 20 (LTS)</td></tr><tr><td><code>nvm install --lts</code></td><td>Instala la última versión LTS</td></tr><tr><td><code>nvm use 20</code></td><td>Activa la versión 20 en la sesión actual</td></tr><tr><td><code>nvm use --lts</code></td><td>Activa la versión LTS actual</td></tr><tr><td><code>nvm ls</code></td><td>Lista todas las versiones instaladas localmente</td></tr><tr><td><code>nvm ls-remote</code></td><td>Lista versiones disponibles para instalar</td></tr><tr><td><code>nvm alias default 20</code></td><td>Establece la versión 20 como predeterminada</td></tr><tr><td><code>nvm current</code></td><td>Muestra la versión activa actualmente</td></tr><tr><td><code>nvm uninstall 18</code></td><td>Desinstala una versión específica</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">💡</p><p><strong>Nota:</strong> Se recomienda siempre usar versiones LTS (Long Term Support) en entornos de producción.</p></div><hr><h2 id="_2-gestion-de-paquetes-con-npm" tabindex="-1">2. Gestión de Paquetes con npm <a class="header-anchor" href="#_2-gestion-de-paquetes-con-npm" aria-label="Permalink to “2. Gestión de Paquetes con npm”">​</a></h2><h3 id="_2-1-inicializar-un-proyecto" tabindex="-1">2.1 Inicializar un proyecto <a class="header-anchor" href="#_2-1-inicializar-un-proyecto" aria-label="Permalink to “2.1 Inicializar un proyecto”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm init</code></td><td>Inicia un proyecto de forma interactiva</td></tr><tr><td><code>npm init -y</code></td><td>Inicia el proyecto con valores predeterminados</td></tr><tr><td><code>npm init --scope=@mi-org</code></td><td>Inicia un paquete con alcance de organización</td></tr></tbody></table><h3 id="_2-2-instalar-paquetes" tabindex="-1">2.2 Instalar paquetes <a class="header-anchor" href="#_2-2-instalar-paquetes" aria-label="Permalink to “2.2 Instalar paquetes”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm install</code></td><td>Instala todas las dependencias del package.json</td></tr><tr><td><code>npm install express</code></td><td>Instala un paquete como dependencia</td></tr><tr><td><code>npm install -D eslint</code></td><td>Instala como dependencia de desarrollo</td></tr><tr><td><code>npm install -g nodemon</code></td><td>Instala un paquete de forma global</td></tr><tr><td><code>npm install express@4.18.2</code></td><td>Instala una versión específica</td></tr><tr><td><code>npm install --production</code></td><td>Instala solo dependencias de producción</td></tr><tr><td><code>npm ci</code></td><td>Instalación limpia y reproducible (ideal para CI/CD)</td></tr></tbody></table><h3 id="_2-3-actualizar-y-desinstalar" tabindex="-1">2.3 Actualizar y desinstalar <a class="header-anchor" href="#_2-3-actualizar-y-desinstalar" aria-label="Permalink to “2.3 Actualizar y desinstalar”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm update</code></td><td>Actualiza todos los paquetes según semver</td></tr><tr><td><code>npm update express</code></td><td>Actualiza un paquete específico</td></tr><tr><td><code>npm uninstall express</code></td><td>Desinstala un paquete</td></tr><tr><td><code>npm uninstall -g nodemon</code></td><td>Desinstala un paquete global</td></tr><tr><td><code>npm outdated</code></td><td>Lista los paquetes con actualizaciones disponibles</td></tr></tbody></table><h3 id="_2-4-auditoria-y-seguridad" tabindex="-1">2.4 Auditoría y seguridad <a class="header-anchor" href="#_2-4-auditoria-y-seguridad" aria-label="Permalink to “2.4 Auditoría y seguridad”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm audit</code></td><td>Analiza vulnerabilidades en las dependencias</td></tr><tr><td><code>npm audit fix</code></td><td>Corrige vulnerabilidades automáticamente</td></tr><tr><td><code>npm audit fix --force</code></td><td>Fuerza correcciones (puede romper compatibilidad)</td></tr><tr><td><code>npm audit --json</code></td><td>Resultado del audit en formato JSON</td></tr></tbody></table><h3 id="_2-5-informacion-de-paquetes" tabindex="-1">2.5 Información de paquetes <a class="header-anchor" href="#_2-5-informacion-de-paquetes" aria-label="Permalink to “2.5 Información de paquetes”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm list</code></td><td>Lista dependencias del proyecto actual</td></tr><tr><td><code>npm list --depth=0</code></td><td>Lista solo dependencias de primer nivel</td></tr><tr><td><code>npm list -g</code></td><td>Lista paquetes instalados globalmente</td></tr><tr><td><code>npm info express</code></td><td>Muestra información detallada de un paquete</td></tr><tr><td><code>npm search lodash</code></td><td>Busca paquetes en el registro de npm</td></tr><tr><td><code>npm view express version</code></td><td>Muestra la versión publicada más reciente</td></tr></tbody></table><h3 id="_2-6-scripts-y-ejecucion" tabindex="-1">2.6 Scripts y ejecución <a class="header-anchor" href="#_2-6-scripts-y-ejecucion" aria-label="Permalink to “2.6 Scripts y ejecución”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm start</code></td><td>Ejecuta el script <code>start</code> del package.json</td></tr><tr><td><code>npm run dev</code></td><td>Ejecuta el script <code>dev</code> personalizado</td></tr><tr><td><code>npm test</code></td><td>Ejecuta los tests definidos en el proyecto</td></tr><tr><td><code>npm run build</code></td><td>Ejecuta el script de construcción</td></tr><tr><td><code>npm run lint</code></td><td>Ejecuta el linter del proyecto</td></tr><tr><td><code>npx &lt;paquete&gt;</code></td><td>Ejecuta un paquete sin instalarlo globalmente</td></tr></tbody></table><hr><h2 id="_3-configuracion-de-npm" tabindex="-1">3. Configuración de npm <a class="header-anchor" href="#_3-configuracion-de-npm" aria-label="Permalink to “3. Configuración de npm”">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>npm config list</code></td><td>Muestra la configuración activa de npm</td></tr><tr><td><code>npm config get registry</code></td><td>Muestra el registro actual de paquetes</td></tr><tr><td><code>npm config set registry &lt;url&gt;</code></td><td>Cambia el registro de paquetes (ej. Nexus, Artifactory)</td></tr><tr><td><code>npm config set cache &lt;ruta&gt;</code></td><td>Define el directorio de caché</td></tr><tr><td><code>npm cache clean --force</code></td><td>Limpia la caché de npm</td></tr><tr><td><code>npm config delete proxy</code></td><td>Elimina una configuración específica</td></tr><tr><td><code>npm config edit</code></td><td>Abre el archivo de configuración en el editor</td></tr><tr><td><code>npm whoami</code></td><td>Muestra el usuario autenticado en el registro</td></tr><tr><td><code>npm login</code></td><td>Inicia sesión en el registro de npm</td></tr><tr><td><code>npm logout</code></td><td>Cierra la sesión del registro actual</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">💡</p><p><strong>Nota:</strong> Usa un archivo <code>.npmrc</code> en la raíz del proyecto para configuración específica por proyecto.</p></div><hr><h2 id="_4-ejecucion-y-administracion-de-procesos" tabindex="-1">4. Ejecución y Administración de Procesos <a class="header-anchor" href="#_4-ejecucion-y-administracion-de-procesos" aria-label="Permalink to “4. Ejecución y Administración de Procesos”">​</a></h2><h3 id="_4-1-ejecucion-basica" tabindex="-1">4.1 Ejecución básica <a class="header-anchor" href="#_4-1-ejecucion-basica" aria-label="Permalink to “4.1 Ejecución básica”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>node app.js</code></td><td>Ejecuta un archivo JavaScript directamente</td></tr><tr><td><code>node -e &quot;console.log(&#39;Hola&#39;)&quot;</code></td><td>Ejecuta código Node.js en línea</td></tr><tr><td><code>node --inspect app.js</code></td><td>Inicia el depurador de Node.js</td></tr><tr><td><code>node --inspect-brk app.js</code></td><td>Depurador que pausa al inicio</td></tr><tr><td><code>node --max-old-space-size=4096 app.js</code></td><td>Aumenta el límite de memoria a 4 GB</td></tr></tbody></table><h3 id="_4-2-pm2-—-gestor-de-procesos-para-produccion" tabindex="-1">4.2 PM2 — Gestor de procesos para producción <a class="header-anchor" href="#_4-2-pm2-—-gestor-de-procesos-para-produccion" aria-label="Permalink to “4.2 PM2 — Gestor de procesos para producción”">​</a></h3><p>PM2 es el estándar de la industria para mantener aplicaciones Node.js en producción:</p><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>pm2 start app.js</code></td><td>Inicia una aplicación con PM2</td></tr><tr><td><code>pm2 start app.js --name api</code></td><td>Inicia con un nombre descriptivo</td></tr><tr><td><code>pm2 start app.js -i max</code></td><td>Inicia en modo cluster (todos los cores)</td></tr><tr><td><code>pm2 list</code></td><td>Lista todos los procesos administrados</td></tr><tr><td><code>pm2 status</code></td><td>Estado detallado de los procesos</td></tr><tr><td><code>pm2 stop api</code></td><td>Detiene un proceso por nombre o ID</td></tr><tr><td><code>pm2 restart api</code></td><td>Reinicia un proceso</td></tr><tr><td><code>pm2 reload api</code></td><td>Recarga sin downtime (zero-downtime)</td></tr><tr><td><code>pm2 delete api</code></td><td>Elimina un proceso de la lista de PM2</td></tr><tr><td><code>pm2 logs</code></td><td>Muestra los logs en tiempo real</td></tr><tr><td><code>pm2 logs api --lines 200</code></td><td>Muestra las últimas 200 líneas de un proceso</td></tr><tr><td><code>pm2 monit</code></td><td>Monitor interactivo de CPU y memoria</td></tr><tr><td><code>pm2 save</code></td><td>Guarda la lista de procesos para auto-arranque</td></tr><tr><td><code>pm2 startup</code></td><td>Genera el script de arranque automático del sistema</td></tr><tr><td><code>pm2 unstartup</code></td><td>Deshabilita el arranque automático</td></tr><tr><td><code>pm2 restart api --update-env</code></td><td>Reinicia actualizando las variables de entorno</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">💡</p><p><strong>Nota:</strong> Ejecuta <code>pm2 save</code> después de cada cambio de configuración para persistir el estado tras un reinicio del servidor.</p></div><hr><h2 id="_5-diagnostico-y-monitoreo" tabindex="-1">5. Diagnóstico y Monitoreo <a class="header-anchor" href="#_5-diagnostico-y-monitoreo" aria-label="Permalink to “5. Diagnóstico y Monitoreo”">​</a></h2><h3 id="_5-1-informacion-del-entorno" tabindex="-1">5.1 Información del entorno <a class="header-anchor" href="#_5-1-informacion-del-entorno" aria-label="Permalink to “5.1 Información del entorno”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>node -p process.versions</code></td><td>Muestra versiones de Node y sus dependencias (V8, OpenSSL, etc.)</td></tr><tr><td><code>node -p process.env</code></td><td>Imprime todas las variables de entorno</td></tr><tr><td><code>node -p process.memoryUsage()</code></td><td>Uso actual de memoria del proceso</td></tr><tr><td><code>node -p os.cpus().length</code></td><td>Número de núcleos disponibles</td></tr><tr><td><code>node -p os.totalmem()</code></td><td>Memoria total del sistema en bytes</td></tr><tr><td><code>node --print &quot;process.platform&quot;</code></td><td>Sistema operativo (linux, darwin, win32)</td></tr></tbody></table><h3 id="_5-2-depuracion-y-profiling" tabindex="-1">5.2 Depuración y profiling <a class="header-anchor" href="#_5-2-depuracion-y-profiling" aria-label="Permalink to “5.2 Depuración y profiling”">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>node --inspect app.js</code></td><td>Activa el depurador remoto (puerto 9229)</td></tr><tr><td><code>node --prof app.js</code></td><td>Genera un perfil de rendimiento (V8)</td></tr><tr><td><code>node --prof-process isolate-*.log</code></td><td>Procesa el log de profiling generado</td></tr><tr><td><code>node --trace-warnings app.js</code></td><td>Muestra el stack trace de cada advertencia</td></tr><tr><td><code>node --experimental-vm-modules</code></td><td>Habilita soporte experimental de ES modules</td></tr><tr><td><code>node --pending-deprecation app.js</code></td><td>Advierte sobre APIs que serán deprecadas</td></tr></tbody></table><hr><h2 id="_6-variables-de-entorno" tabindex="-1">6. Variables de Entorno <a class="header-anchor" href="#_6-variables-de-entorno" aria-label="Permalink to “6. Variables de Entorno”">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td><code>NODE_ENV=production node app.js</code></td><td>Establece el entorno de ejecución</td></tr><tr><td><code>NODE_ENV=development node app.js</code></td><td>Modo desarrollo (más logs, sin optimizaciones)</td></tr><tr><td><code>PORT=8080 node app.js</code></td><td>Define el puerto de escucha</td></tr><tr><td><code>NODE_OPTIONS=--max-old-space-size=4096</code></td><td>Opciones globales para todos los procesos Node</td></tr><tr><td><code>DEBUG=express:* node app.js</code></td><td>Activa logs de debug de módulos que usan <code>debug</code></td></tr><tr><td><code>NODE_TLS_REJECT_UNAUTHORIZED=0</code></td><td>Deshabilita verificación TLS (¡solo para desarrollo!)</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">💡</p><p><strong>Nota:</strong> Usa archivos <code>.env</code> junto con la librería <code>dotenv</code> o el flag <code>--env-file</code> (Node 20+) para gestionar variables de entorno de forma segura.</p></div><hr><h2 id="_7-referencia-rapida-—-flujo-de-trabajo" tabindex="-1">7. Referencia Rápida — Flujo de Trabajo <a class="header-anchor" href="#_7-referencia-rapida-—-flujo-de-trabajo" aria-label="Permalink to “7. Referencia Rápida — Flujo de Trabajo”">​</a></h2><p>Ciclo típico de administración en producción:</p><ol><li>Clonar repositorio e instalar: <code>npm ci</code></li><li>Construir la aplicación: <code>npm run build</code></li><li>Iniciar con PM2: <code>pm2 start dist/index.js --name mi-app -i max</code></li><li>Configurar arranque automático: <code>pm2 save &amp;&amp; pm2 startup</code></li><li>Monitorear: <code>pm2 monit</code></li><li>Actualizar sin downtime: <code>git pull &amp;&amp; npm ci &amp;&amp; npm run build &amp;&amp; pm2 reload mi-app</code></li><li>Revisar logs ante errores: <code>pm2 logs mi-app --lines 500</code></li><li>Auditar seguridad periódicamente: <code>npm audit</code></li></ol><blockquote><p>💡 <strong>Nota:</strong> Siempre usa <code>npm ci</code> en lugar de <code>npm install</code> en servidores y pipelines de CI/CD para garantizar instalaciones reproducibles y deterministas.</p></blockquote><p><a href="./programacion.html">Manual Node JS</a></p>',52)])])}const h=e(r,[["render",i]]);export{u as __pageData,h as default};
